import React, { useState, useEffect } from 'react';
import { useReactTable , flexRender } from '@tanstack/react-table';

const MaterialList = () => {
  const [materials, setMaterials] = useState([]);

  useEffect(() => {
    fetchMaterials();
  }, []);

  const fetchMaterials = () => {
    fetch('http://localhost:8081/')
      .then((response) => response.json())
      .then((data) => setMaterials(data))
      .catch((error) => console.log('Error:', error));
  };

  const columns = [
    { header: 'Material ID', accessorKey: 'matid' },
    { header: 'Name', accessorKey: 'name' },
    { header: 'Description', accessorKey: 'description' },
    { header: 'Unit of Measure', accessorKey: 'unit_of_measure' },
    { header: 'Price per Unit', accessorKey: 'price_per_unit' },
    { header: 'Recent Vendor', accessorKey: 'recent_vendor' },
  ];

  const tableInstance = useReactTable ({ columns, data: materials });

  const { getTableProps, getTableBodyProps, headerGroups, rows, prepareRow } = tableInstance;

  return (
    <div>
      <table {...getTableProps()} className="table">
        <thead>
          {headerGroups.map((headerGroup) => (
            <tr {...headerGroup.getHeaderGroupProps()}>
              {headerGroup.headers.map((column) => (
                <th colSpan={column.colSpan} key={column.id}>
                  {flexRender(column.header, column.getContext())}
                </th>
              ))}
            </tr>
          ))}
        </thead>
        <tbody {...getTableBodyProps()}>
          {rows.map((row) => {
            prepareRow(row);
            return (
              <tr {...row.getRowProps()}>
                {row.cells.map((cell) => (
                  <td key={cell.id}>
                    {flexRender(cell.column.cell, cell.getContext())}
                  </td>
                ))}
              </tr>
            );
          })}
        </tbody>
      </table>
    </div>
  );
};

export default MaterialList;
